import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as l,c as a,e}from"./app-01aedd85.js";const r={},d=e('<h1 id="分布式rag系统" tabindex="-1"><a class="header-anchor" href="#分布式rag系统" aria-hidden="true">#</a> 分布式RAG系统</h1><p>分布式RAG系统，是指将RAG的各个模块（文档处理、Embedding、向量存储、检索、生成）部<br> 署在多个节点，实现负载均衡和高可用，适配大数据量、高并发场景；文档增量更新指新增、修改、删除<br> 文档时，无需重建整个向量索引，仅更新相关向量；实时检索指用户查询后，能在500ms内返回检索结<br> 果；多节点部署的核心问题是向量一致性（各节点的向量数据同步）和检索延迟（节点间通信耗时）。</p><h3 id="一、为什么需要分布式" tabindex="-1"><a class="header-anchor" href="#一、为什么需要分布式" aria-hidden="true">#</a> 一、为什么需要分布式</h3><p>百万级以上文档的RAG系统，单机部署无法满足高并发、大数据量的需求，必须采用分布式部<br> 署；若无法实现增量更新，每次文档变更都需重建索引，耗时极长（数小时甚至数天），影响系统可用<br> 性；若向量不一致，会导致不同节点检索结果不同，影响用户体验；若检索延迟过高，无法满足高并发场<br> 景的响应需求。</p><h3 id="一、文档增量更新实现-核心-增量索引-消息通知" tabindex="-1"><a class="header-anchor" href="#一、文档增量更新实现-核心-增量索引-消息通知" aria-hidden="true">#</a> 一、文档增量更新实现（核心：增量索引+消息通知）</h3><ol><li>增量更新架构：采用“文档采集→预处理→Embedding→增量索引→消息通知”的流程，用Kafka消息队列实现各模块的异步通信；</li><li>具体步骤：<br><strong>文档采集</strong>：通过定时任务、API接口，采集新增、修改、删除的文档，将文档信息（如文档ID、内容、操作类型）发送至Kafka消息队列；<br><strong>预处理与Embedding</strong>：消费者监听Kafka消息，对新增/修改的文档进行预处理、Embedding转换，生成向量；对删除的文档，记录文档ID和对应的向量ID；<br> **增量索引：**将新增/修改的向量，增量写入Milvus分布式向量数据库，无需重建整个索引；对删除的文档，删除对应的向量和索引；<br> **消息通知：**增量更新完成后，发送消息至检索模块，通知索引已更新，确保检索时能获取最新数据。</li><li>优化：对批量新增的文档，采用“批量Embedding+批量增量索引”，提升更新效率；对高频修改的文档，设置更新缓存，避免频繁写入数据库。</li></ol><h3 id="二、实时检索实现-核心-分层缓存-负载均衡" tabindex="-1"><a class="header-anchor" href="#二、实时检索实现-核心-分层缓存-负载均衡" aria-hidden="true">#</a> 二、实时检索实现（核心：分层缓存+负载均衡）</h3><ol><li>检索架构：采用“本地缓存→节点检索→结果聚合”的分层检索逻辑，减少节点间通信耗时；</li><li>具体步骤：</li></ol><ul><li>**本地缓存：**每个检索节点将高频查询的检索结果（如Top10结果）缓存至Redis，缓存有效期设置为10-30分钟，用户查询时先查询本地缓存，命中则直接返回，无需跨节点检索；</li><li>**节点检索：**若本地缓存未命中，根据查询向量的哈希值，路由至对应的Milvus数据节点（避免跨节点检索），该节点检索本地存储的向量，返回结果；</li><li>**结果聚合：**若查询需要多节点数据（如跨分片检索），由协调节点聚合各数据节点的检索结果，进行重排序后返回给用户；</li></ul><ol start="3"><li>优化：采用“就近路由”策略，将用户查询路由至距离最近的数据节点，减少网络延迟；对检索结果进行预计算，提升重排序效率。</li></ol><h3 id="三、多节点向量一致性解决-核心-主从同步-校验机制" tabindex="-1"><a class="header-anchor" href="#三、多节点向量一致性解决-核心-主从同步-校验机制" aria-hidden="true">#</a> 三、多节点向量一致性解决（核心：主从同步+校验机制）</h3><ol><li>**主从同步架构：**Milvus采用“主节点+从节点”架构，主节点负责向量的写入、更新、删除，从节点负责数据备份和检索；</li><li>**同步机制：**主节点完成向量更新后，通过“日志同步”将更新操作同步至所有从节点，确保各节点的向量数据一致；同步延迟控制在100ms以内；</li><li>**校验机制：**定期（如每小时）对各节点的向量数据进行校验，对比向量的哈希值和数量，若发现不一致，触发自动同步，确保数据一致性；</li><li>**容错机制：**若主节点故障，自动切换至从节点，避免数据丢失和服务中断。</li></ol><h3 id="四、检索延迟优化-核心-减少节点通信-索引优化" tabindex="-1"><a class="header-anchor" href="#四、检索延迟优化-核心-减少节点通信-索引优化" aria-hidden="true">#</a> 四、检索延迟优化（核心：减少节点通信+索引优化）</h3><ol><li><p>**索引优化：**采用“IVF_PQ+HNSW混合索引”，提升单节点的检索速度；同时对向量进行降维，减少数据传输量；</p></li><li><p>**节点部署：**将检索节点、向量数据库节点、生成节点部署在同一局域网，减少跨网络通信耗时；</p></li><li><p>**并发控制：**采用分布式锁，避免多个节点同时处理同一查询，减少资源竞争；同时限制单个节点的并发请求数，避免节点过载；</p></li><li><p>**数据分片：**将向量数据按领域、文档类型进行分片，存储在不同节点，检索时仅访问对应分片，减少检索范围。</p></li><li><p>增量更新时需做好数据校验，避免新增/修改的向量错误，导致检索结果偏差；</p></li><li><p>缓存有效期需合理设置，避免缓存过期导致的检索结果过时；</p></li><li><p>主从同步需监控同步延迟，若延迟过高，需排查网络或节点负载问题；</p></li><li><p>数据分片需合理，避免某一分片数据量过大，导致该节点过载。</p></li></ol>',14),h=[d];function n(o,t){return l(),a("div",null,h)}const p=i(r,[["render",n],["__file","24、分布式RAG系统.html.vue"]]);export{p as default};
